var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"엇차!","JPN":"おっと！","ENG":"Oopsie!","TWN":"嘿咻！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배?!","JPN":"先輩！？","ENG":"Shiyoon?!","TWN":"前輩？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다행히 늦지 않았나 보군요. 다친 곳은 없으신가요, 미나 양?","JPN":"なんとか間に合ったようですね。怪我はないですか、ミナさん？","ENG":"I’m glad I got here in time. Are you hurt, Mina?","TWN":"幸好有趕上。米娜，你沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어떻게 여기에……? 설마 우리 뒤를 따라온 거야?","JPN":"どうしてここに……？　まさか、私たちの後を追ってきたの？","ENG":"How did you get here? Did you follow us?","TWN":"前輩怎麼會……？你跟蹤我們嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네. 아무래도 수상해서 말이죠.","JPN":"はい、どうも気になることがありまして。","ENG":"Yes, I felt something was off.","TWN":"對啊，總覺得不太對勁。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"최근 경험상 미나 양에게 이상한 관심을 가진 자들이 좋은 의도를 가진 경우가 별로 없었거든요.","JPN":"これまでの経験上、ミナさんに純粋な気持ちで興味を示す人は\\nほとんどいませんでした。","ENG":"From my recent experience, people with a particular interest in you rarely have good intentions.","TWN":"根據我最近的經驗，會主動找上米娜的人，通常都沒安什麼好心眼。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고작 그런 이유로 작전을 포기하고 왔다고?","JPN":"そんな理由で作戦を放棄してここに来たの？","ENG":"That’s the only reason why you gave up your mission?","TWN":"只是因為這樣，你就放棄任務跑來這裡？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그리고 슬쩍 지나가듯 말하긴 했지만, 미나 양과 닮았다는 샬롯 양의 고향친구 분 말이죠.","JPN":"それから、先ほどシャーロットさんがミナさんに似ていると仰っていた、\\n故郷のご友人のことですが……","ENG":"Also, about that friend of Carlota’s who resembles you...","TWN":"不只是這樣，雖然她只有稍微提到，但她在提起長得和你很像的朋友時，"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그녀를 <color=#ffd34c>늑대</color>라고 부르는 걸 들었거든요.","JPN":"彼女のことを<color=#ffd34c>狼</color>と呼んだのを聞きました。","ENG":"I heard that Carlota called her <color=#ffd34c>the Wolf</color>.","TWN":"我聽到她說<color=#ffd34c>狼</color>。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"지난번에도 말했었지만 전 귀가 좋으니까요.","JPN":"この前もお話ししましたが、僕は地獄耳ですので。","ENG":"Like I said, I've got good hearing.","TWN":"我上次也有說過，我的耳朵很敏銳。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"늑대? 설마……?","JPN":"狼？　まさか……？","ENG":"The Wolf? Does that mean...","TWN":"狼？該不會……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양을 늑대라고 부르던 자들은 그리 많지 않죠.","JPN":"ミナさんを狼と呼ぶ人はそう多くありません。","ENG":"Not many people call you the Wolf, Mina.","TWN":"應該很少人會叫你狼吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"샬롯 양. 당신도 그들의 일원이 아닌가요?","JPN":"シャーロットさん、あなたも彼らの一員ですね？","ENG":"Carlota, do you happen to be one of them?","TWN":"夏洛特，你和他們是一夥的對吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"……내 이름은 샬롯 마르티네즈.","JPN":"……我が名はシャーロット・マルチネス。","ENG":"... My name is Carlota Martinez.","TWN":"……我叫夏洛特 馬汀尼茲。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"구원 기사단의 일원이며 몰락한 가문의 영광을 위해 종군하는 최후의 후계자다.","JPN":"救世騎士団の一員であり、没落した一族の栄光のために従軍する\\n最期の後継者だ。","ENG":"I am one of the Knights of Redemption, the last heir of the fallen house who seeks to raise my family's banner once again.","TWN":"屬於救贖騎士團的一員，是沒落家族最後的繼承者，因為要復興家族而從軍。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"구원기사단! 그 녀석들과 한패라고?!","JPN":"救世騎士団！　あいつらの仲間なの！？","ENG":"The Knights of Redemption! You’re one of them?","TWN":"救贖騎士團！你和他們是一夥的嗎？！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"과연, 그래서 나와 미나 양을 떼어놓고 습격하려고 한 거군요.","JPN":"なるほど、それで僕とミナさんを引き離して襲おうとしたんですね。","ENG":"So that’s why you separated us and attacked her.","TWN":"我就知道，所以你才故意把我跟米娜分開，想趁機攻擊她對吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아마 조난자를 이 곳에 배치해 둔 것도 그녀가 준비한 유인책이었겠죠.","JPN":"恐らく遭難者も彼女が仕込んだ罠でしょう。","ENG":"This castaway here must be part of her trap, as well.","TWN":"這個所謂的遇難者也是你事先安排好的吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"미안하다. 하지만 난 가문의 불명예를 씻어내기 위해서 의무를 다할 뿐.","JPN":"すまない。だが私は一族の不名誉を晴らすため、義務を果たさなければならない。","ENG":"I am sorry. But I have to do everything to clear my family's name.","TWN":"抱歉，但我有義務要洗清家族的汙名。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"내 임무에 따라 결투를 청한다!","JPN":"よって、決闘を申し込む！","ENG":"Now, according to my duty, I challenge you to a duel!","TWN":"照我的任務跟我決鬥吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"늑대……! 아니, 유미나!","JPN":"狼……！　いや、ヤナギ・ミナ！","ENG":"Wolf... No, Yoo Mina!","TWN":"狼……！不對，劉米娜！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};